Soit le code suivant : <br><pre><code>const EventEmitter = require('events');
const monEmitter = new EventEmitter();

monEmitter.on('salut', (nom) => {
  console.log(`Bonjour ${nom}`);
});

// Quelle ligne déclenche l'affichage ?
</code></pre>

Que produit le code suivant ? <br><pre><code>const { Readable } = require('stream');
const readable = Readable.from(['A', 'B', 'C']);
readable.on('data', (chunk) => {
  console.log(chunk);
});
</code></pre>
